update appuser
set    password = #{password}, mbti_type_id = #{mbtiTypeId}, ufile = #{ufile}, nickname = #{nickname},
mobile = #{mobile}, provider = #{provider}, provider_id = #{providerId}
where app_user_id = #{appUserId};
